#include <stdio.h>
#include <string.h>

char* minWindow(char* s, char* t) {
    int tCount[128] = {0};
    int required = strlen(t);
    for (int i = 0; i < required; i++) {
        tCount[t[i]]++;
    }
    int l = 0, r = 0;
    int formed = 0;
    int windowCounts[128] = {0};
    int ans[3] = { -1, 0, 0 };
    while (r < strlen(s)) {
        char c = s[r];
        windowCounts[c]++;
        if (tCount[c] > 0 && windowCounts[c] <= tCount[c]) {
            formed++;
        }
        while (l <= r && formed == required) {
            c = s[l];
            if (ans[0] == -1 || r - l + 1 < ans[0]) {
                ans[0] = r - l + 1;
                ans[1] = l;
                ans[2] = r;
            }
            windowCounts[s[l]]--;
            if (tCount[s[l]] > 0 && windowCounts[s[l]] < tCount[s[l]]) {
                formed--;
            }
            l++;
        }
        r++;
    }
    return ans[0] == -1 ? "" : strncpy((char*)malloc(ans[0] + 1), s + ans[1], ans[0]);
}

